// In a page handler or API handler
return ctx.sse(async (send) => {
  // Send an event every second for 10 seconds
  for (let i = 0; i < 10; i++) {
    await send({ data: { tick: i }, event: "tick" });
    await new Promise(r => setTimeout(r, 1000));
  }
});

interface SSEEvent {
  data: unknown;          // serialized to JSON
  event?: string;        // event type (default: "message")
  id?: string | number;  // last-event-id for reconnection
  retry?: number;        // reconnect delay hint in ms
}

import { useEffect, useState } from "preact/hooks";

export default function LiveFeed() {
  const [events, setEvents] = useState<string[]>([]);

  useEffect(() => {
    const es = new EventSource("/api/public/live-feed");

    es.addEventListener("update", (e) => {
      const data = JSON.parse(e.data);
      setEvents(prev => [...prev, data.message]);
    });

    es.onerror = () => es.close();

    return () => es.close();
  }, []);

  return (
    <ul>
      {events.map((e, i) => <li key={i}>{e}</li>)}
    </ul>
  );
}
